let state = {
  messegData: [
    {
      id: 1,
      messege: "How are you?",
      like: 11,
    },
    {
      id: 2,
      messege: "Nice!",
      like: 21,
    },
    {
      id: 3,
      messege: "What's you name?",
      like: 2,
    },
  ],
};

const addPost = (newMessege) => {
  state.messegData.push(newMessege);
};

export default state;
